const ticket = $json.body || $json;
const text = String(ticket.message || ticket.subject || '').toLowerCase();
let team = 'general-support';
let priority = 'normal';

// STUDENT EDIT AREA:
// Add more routing rules here.
if (text.includes('refund') || text.includes('billing') || text.includes('payment')) team = 'finance';
if (text.includes('error') || text.includes('bug') || text.includes('broken')) team = 'technical-support';
if (text.includes('urgent') || text.includes('critical') || text.includes('down')) priority = 'high';

return [{
  json: {
    ticket_id: ticket.ticket_id || `ticket-${Date.now()}`,
    customer: ticket.name || 'Customer',
    routed_to: team,
    priority,
    original_message: ticket.message || '',
    classroom_note: 'Ticket was routed by simple rules for class practice.'
  }
}];
